INSERT INTO public.neuron_templates (name, description, category, blocks_template, is_public, usage_count, default_tags) VALUES ('LSHP: Formula Generală pe 10 Pași', 'Logica Strategică de Hipnotizare Persuasivă desfășurată complet: de la ambiguitate controlată la ancora memorabilă, cu variații.', 'Codul Cușnir', '[{"type":"heading","content":"LSHP — Formula Generală pe 10 Pași"},{"type":"text","content":"Fiecare pas construit cu intenție clară și secvență precisă pentru impact maxim."},{"type":"subheading","content":"Pasul 1: Curiozitate prin Ambiguitate Controlată"},{"type":"text","content":"Începe cu un paradox: Cea mai mare minciună pe care ai fost învățat să o crezi despre [subiect]..."},{"type":"subheading","content":"Pasul 2: Contraste Puternice"},{"type":"text","content":"Descrie starea actuală vizual, apoi noua realitate."},{"type":"subheading","content":"Pasul 3: Descompune Paradoxul"},{"type":"text","content":"Pare imposibil? Dar ce ar fi dacă [soluție simplificată]?"},{"type":"subheading","content":"Pasul 4: Marele Secret"},{"type":"text","content":"Există o tehnică pe care 95% nu o folosesc..."},{"type":"subheading","content":"Pasul 5: Expune Problemele Mai Bine Decât Ei"},{"type":"text","content":"Descrie durerea cu precizie înfricoșătoare."},{"type":"subheading","content":"Pasul 6: Micronarațiuni"},{"type":"text","content":"Poveste scurtă hiper-relevantă despre transformare."},{"type":"subheading","content":"Pasul 7: Întrebări Retorice"},{"type":"text","content":"Cât de diferită ar fi viața ta dacă [rezultatul dorit]?"},{"type":"subheading","content":"Pasul 8: Superputere și Slăbiciune"},{"type":"text","content":"La început, și eu am fost sceptic. Dar rezultatele..."},{"type":"subheading","content":"Pasul 9: Apel la Acțiune Inovativ"},{"type":"text","content":"Viziune captivantă, nu CTA generic."},{"type":"subheading","content":"Pasul 10: Ancora Memorabilă"},{"type":"text","content":"Frază-refren care rămâne în minte."},{"type":"divider","content":""},{"type":"subheading","content":"Variații"},{"type":"idea","content":"Educație: Deschidere contraintuitivă → Contrast → Reflecție"},{"type":"idea","content":"Emoțională: Durere → Poveste → Apel empatic"},{"type":"idea","content":"Date: Statistică → Abordare inovativă → Secret cu procent"}]'::jsonb, true, 0, ARRAY['LSHP','hipnotizare','persuasiune','10 pași']);